// START__FN_PARSE_SESSION_FOR_INLINE (универсальный)

// где может лежать строка/объект сессии
const raw =
  $json.session ??
  $json.variant_raw ??          // <-- ВАЖНО: твой текущий кейс
  $json.redis?.session ??
  $json.redis?.data ??
  $json.data ??
  $json.session_raw ??
  null;

let sess = {};

try {
  let parsed = raw;

  // если пришёл объект — ок
  // если пришла строка — парсим (иногда бывает "JSON в JSON", поэтому два раза)
  if (typeof parsed === "string") parsed = JSON.parse(parsed);
  if (typeof parsed === "string") parsed = JSON.parse(parsed);

  // иногда PG/Redis возвращают массив строк/объектов
  if (Array.isArray(parsed)) parsed = parsed[0];

  if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
    sess = parsed;
  }
} catch (e) {
  sess = {};
}

// дефолты/нормализация
sess.active_request_id = sess.active_request_id ?? null;
sess.awaiting = sess.awaiting ?? "none";
sess.current_variant_idx = sess.current_variant_idx ?? "0";
sess.last_variant_idx = sess.last_variant_idx ?? "0";
sess.recipient_name = sess.recipient_name ?? null;
sess.last_inline_message_id = sess.last_inline_message_id ?? null;

return [{ json: { ...$json, session: sess } }];

let session = $json.session;
if (!session || typeof session !== "object") session = {};

const resp = $json.body ?? $json; // если HTTP Request возвращает full response

const msgId =
  resp.result?.message_id ??
  resp.message_id ??
  null;

if (msgId) {
  session.last_inline_message_id = String(msgId);
}

return [{ json: { ...$json, session } }];
